#include <numeric>
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int connectSticks(vector<int>& sticks) {
        priority_queue<int, vector<int>, greater<int>> pq;
        for (int stick : sticks) {
            pq.push(stick);
        }
        int cost = 0;
        while (pq.size() > 1) {
            int a = pq.top();
            pq.pop();
            int b = pq.top();
            pq.pop();
            int sum = a + b;
            cost += sum;
            pq.push(sum);
        }
        return cost;
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> sticks(n);
    for (int i = 0; i < n; i++) cin >> sticks[i];
    Solution sol;
    int ans = sol.connectSticks(sticks);
    cout << ans << "\n";
    return 0;
}
